local AUTHOR = "td1madao" local ACTIONSPACE = "td1madao_global" local ACTION = "td1madao_global_all" local CHAR = CHAR local function createElement(obj, child, element)     if not obj or not tdNotEmpty(child) then         return     end     if not obj[child] then         obj[child] = element or {}     end     return obj[child] end local td1madao_try_class = Class(function() end) function td1madao_try_class:__call(tryfun, ...)     local success = true     _G.xpcall(tryfun, function()         success = false     end, ...)     return success end local td1madao_try = td1madao_try_class() if not td1madao_try(function()     local a = _G.TD end) then     _G.TD = {} end TD = _G.TD local TD = _G.TD createElement(createElement(TD, AUTHOR), CHAR) local modField = TD[AUTHOR][CHAR] modField.CHAR = CHAR if not modField["createFn"] then     modField["createFn"] = function(name, fn)         if not name or not fn then             return         end         if modField[name] then             return         end         modField[name] = fn     end end modField.createFn("default", function(obj, child, element)     return createElement(obj, child, element) end) modField.createFn("try", function(tryfun, ...)     return td1madao_try(tryfun, ...) end) modField.AUTHOR = AUTHOR modField.ACTIONSPACE = ACTIONSPACE modField.ACTION = ACTION 